const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.urlencoded({ extended: true }));
app.use(bodyParser.json());

const clients = {
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret'
};

const authorizationCodes = {};

const redirectUriWhitelist = [
  'http://localhost:3000/callback',
  // Add other allowed redirect URIs here
];

app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, state } = req.query;

  if (response_type !== 'code' || client_id !== clients.clientId) {
    return res.status(400).send('Invalid request');
  }

  if (!redirectUriWhitelist.includes(redirect_uri)) {
    return res.status(400).send('Redirect URI not allowed');
  }

  const authorizationCode = crypto.randomBytes(20).toString('hex');

  authorizationCodes[authorizationCode] = { redirect_uri, state };

  res.redirect(`${redirect_uri}?code=${authorizationCode}&state=${state}`);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri } = req.body;

  if (grant_type !== 'authorization_code' || !authorizationCodes[code]) {
    return res.status(400).send('Invalid request');
  }

  const { redirect_uri: storedRedirectUri, state } = authorizationCodes[code];

  if (redirect_uri !== storedRedirectUri) {
    return res.status(400).send('Invalid redirect URI');
  }

  delete authorizationCodes[code];

  // Generate access token and refresh token
  const accessToken = crypto.randomBytes(20).toString('hex');
  const refreshToken = crypto.randomBytes(20).toString('hex');

  res.json({
    access_token: accessToken,
    refresh_token: refreshToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

const PORT = process.env.PORT || 4000;
app.listen(PORT, () => {
  console.log(`Authorization server running on port ${PORT}`);
});